#include "red_black_tree.h"
#include <stdlib.h>

#define RB_RED 1
#define RB_BLACK 0

typedef struct RBNode {
    int key;
    struct RBNode* left;
    struct RBNode* right;
    struct RBNode* parent;
    int color;
} RBNode;

static RBNode* root_g;

static RBNode* create_node(int key) {
    RBNode* node = (RBNode*)malloc(sizeof(RBNode));
    node->key = key;
    node->left = NULL;
    node->right = NULL;
    node->parent = NULL;
    node->color = RB_RED;
    return node;
}

static void rotate_left(RBNode* x) {
    RBNode* y = x->right;
    x->right = y->left;
    if (y->left) y->left->parent = x;
    y->parent = x->parent;
    if (!x->parent) root_g = y;
    else if (x == x->parent->left) x->parent->left = y;
    else x->parent->right = y;
    y->left = x;
    x->parent = y;
}

static void rotate_right(RBNode* x) {
    RBNode* y = x->left;
    x->left = y->right;
    if (y->right) y->right->parent = x;
    y->parent = x->parent;
    if (!x->parent) root_g = y;
    else if (x == x->parent->right) x->parent->right = y;
    else x->parent->left = y;
    y->right = x;
    x->parent = y;
}

static void fix_insert(RBNode* z) {
    while (z->parent && z->parent->color == RB_RED) {
        RBNode* gp = z->parent->parent;
        if (z->parent == gp->left) {
            RBNode* y = gp->right;
            if (y && y->color == RB_RED) {
                z->parent->color = RB_BLACK;
                y->color = RB_BLACK;
                gp->color = RB_RED;
                z = gp;
            } else {
                if (z == z->parent->right) {
                    z = z->parent;
                    rotate_left(z);
                }
                z->parent->color = RB_BLACK;
                z->parent->parent->color = RB_RED;
                rotate_right(z->parent->parent);
            }
        } else {
            RBNode* y = gp->left;
            if (y && y->color == RB_RED) {
                z->parent->color = RB_BLACK;
                y->color = RB_BLACK;
                gp->color = RB_RED;
                z = gp;
            } else {
                if (z == z->parent->left) {
                    z = z->parent;
                    rotate_right(z);
                }
                z->parent->color = RB_BLACK;
                z->parent->parent->color = RB_RED;
                rotate_left(z->parent->parent);
            }
        }
    }
    root_g->color = RB_BLACK;
}

static void insert_key(int key) {
    RBNode* y = NULL;
    RBNode* x = root_g;
    while (x) {
        y = x;
        if (key < x->key) x = x->left;
        else if (key > x->key) x = x->right;
        else return;
    }
    RBNode* node = create_node(key);
    node->parent = y;
    if (!y) root_g = node;
    else if (key < y->key) y->left = node;
    else y->right = node;
    fix_insert(node);
}

static void inorder(RBNode* node, int* result, int* idx) {
    if (!node) return;
    inorder(node->left, result, idx);
    result[(*idx)++] = node->key;
    inorder(node->right, result, idx);
}

static void free_tree(RBNode* node) {
    if (!node) return;
    free_tree(node->left);
    free_tree(node->right);
    free(node);
}

void rb_insert_inorder(const int* arr, int n, int* result, int* result_size) {
    root_g = NULL;
    for (int i = 0; i < n; i++) insert_key(arr[i]);
    *result_size = 0;
    inorder(root_g, result, result_size);
    free_tree(root_g);
    root_g = NULL;
}

#include <vector>

enum Color { RED, BLACK };

struct RBNode {
    int key;
    RBNode* left;
    RBNode* right;
    RBNode* parent;
    Color color;
    RBNode(int k) : key(k), left(nullptr), right(nullptr), parent(nullptr), color(RED) {}
};

static RBNode* root_ptr;

static void rotateLeft(RBNode* x) {
    RBNode* y = x->right;
    x->right = y->left;
    if (y->left) y->left->parent = x;
    y->parent = x->parent;
    if (!x->parent) root_ptr = y;
    else if (x == x->parent->left) x->parent->left = y;
    else x->parent->right = y;
    y->left = x;
    x->parent = y;
}

static void rotateRight(RBNode* x) {
    RBNode* y = x->left;
    x->left = y->right;
    if (y->right) y->right->parent = x;
    y->parent = x->parent;
    if (!x->parent) root_ptr = y;
    else if (x == x->parent->right) x->parent->right = y;
    else x->parent->left = y;
    y->right = x;
    x->parent = y;
}

static void fixInsert(RBNode* z) {
    while (z->parent && z->parent->color == RED) {
        RBNode* gp = z->parent->parent;
        if (z->parent == gp->left) {
            RBNode* y = gp->right;
            if (y && y->color == RED) {
                z->parent->color = BLACK;
                y->color = BLACK;
                gp->color = RED;
                z = gp;
            } else {
                if (z == z->parent->right) {
                    z = z->parent;
                    rotateLeft(z);
                }
                z->parent->color = BLACK;
                z->parent->parent->color = RED;
                rotateRight(z->parent->parent);
            }
        } else {
            RBNode* y = gp->left;
            if (y && y->color == RED) {
                z->parent->color = BLACK;
                y->color = BLACK;
                gp->color = RED;
                z = gp;
            } else {
                if (z == z->parent->left) {
                    z = z->parent;
                    rotateRight(z);
                }
                z->parent->color = BLACK;
                z->parent->parent->color = RED;
                rotateLeft(z->parent->parent);
            }
        }
    }
    root_ptr->color = BLACK;
}

static void insertNode(int key) {
    RBNode* y = nullptr;
    RBNode* x = root_ptr;
    while (x) {
        y = x;
        if (key < x->key) x = x->left;
        else if (key > x->key) x = x->right;
        else return;
    }
    RBNode* node = new RBNode(key);
    node->parent = y;
    if (!y) root_ptr = node;
    else if (key < y->key) y->left = node;
    else y->right = node;
    fixInsert(node);
}

static void inorder(RBNode* node, std::vector<int>& result) {
    if (!node) return;
    inorder(node->left, result);
    result.push_back(node->key);
    inorder(node->right, result);
}

static void freeTree(RBNode* node) {
    if (!node) return;
    freeTree(node->left);
    freeTree(node->right);
    delete node;
}

std::vector<int> rb_insert_inorder(std::vector<int> arr) {
    root_ptr = nullptr;
    for (int val : arr) insertNode(val);
    std::vector<int> result;
    inorder(root_ptr, result);
    freeTree(root_ptr);
    root_ptr = nullptr;
    return result;
}

using System.Collections.Generic;

public class RedBlackTree
{
    private class Node
    {
        public int Key;
        public Node Left, Right, Parent;
        public bool IsRed;
        public Node(int key) { Key = key; IsRed = true; }
    }

    private static Node root;

    private static void RotateLeft(Node x)
    {
        Node y = x.Right;
        x.Right = y.Left;
        if (y.Left != null) y.Left.Parent = x;
        y.Parent = x.Parent;
        if (x.Parent == null) root = y;
        else if (x == x.Parent.Left) x.Parent.Left = y;
        else x.Parent.Right = y;
        y.Left = x;
        x.Parent = y;
    }

    private static void RotateRight(Node x)
    {
        Node y = x.Left;
        x.Left = y.Right;
        if (y.Right != null) y.Right.Parent = x;
        y.Parent = x.Parent;
        if (x.Parent == null) root = y;
        else if (x == x.Parent.Right) x.Parent.Right = y;
        else x.Parent.Left = y;
        y.Right = x;
        x.Parent = y;
    }

    private static void FixInsert(Node z)
    {
        while (z.Parent != null && z.Parent.IsRed)
        {
            Node gp = z.Parent.Parent;
            if (z.Parent == gp.Left)
            {
                Node y = gp.Right;
                if (y != null && y.IsRed)
                {
                    z.Parent.IsRed = false;
                    y.IsRed = false;
                    gp.IsRed = true;
                    z = gp;
                }
                else
                {
                    if (z == z.Parent.Right) { z = z.Parent; RotateLeft(z); }
                    z.Parent.IsRed = false;
                    z.Parent.Parent.IsRed = true;
                    RotateRight(z.Parent.Parent);
                }
            }
            else
            {
                Node y = gp.Left;
                if (y != null && y.IsRed)
                {
                    z.Parent.IsRed = false;
                    y.IsRed = false;
                    gp.IsRed = true;
                    z = gp;
                }
                else
                {
                    if (z == z.Parent.Left) { z = z.Parent; RotateRight(z); }
                    z.Parent.IsRed = false;
                    z.Parent.Parent.IsRed = true;
                    RotateLeft(z.Parent.Parent);
                }
            }
        }
        root.IsRed = false;
    }

    private static void Insert(int key)
    {
        Node y = null, x = root;
        while (x != null)
        {
            y = x;
            if (key < x.Key) x = x.Left;
            else if (key > x.Key) x = x.Right;
            else return;
        }
        Node node = new Node(key) { Parent = y };
        if (y == null) root = node;
        else if (key < y.Key) y.Left = node;
        else y.Right = node;
        FixInsert(node);
    }

    private static void Inorder(Node node, List<int> result)
    {
        if (node == null) return;
        Inorder(node.Left, result);
        result.Add(node.Key);
        Inorder(node.Right, result);
    }

    public static int[] RbInsertInorder(int[] arr)
    {
        root = null;
        foreach (int val in arr) Insert(val);
        var result = new List<int>();
        Inorder(root, result);
        return result.ToArray();
    }
}

