const (
	red   = true
	black = false
)

type rbNode struct {
	key    int
	left   *rbNode
	right  *rbNode
	parent *rbNode
	color  bool
}

var rbRoot *rbNode

func rotateLeftRB(x *rbNode) {
	y := x.right
	x.right = y.left
	if y.left != nil {
		y.left.parent = x
	}
	y.parent = x.parent
	if x.parent == nil {
		rbRoot = y
	} else if x == x.parent.left {
		x.parent.left = y
	} else {
		x.parent.right = y
	}
	y.left = x
	x.parent = y
}

func rotateRightRB(x *rbNode) {
	y := x.left
	x.left = y.right
	if y.right != nil {
		y.right.parent = x
	}
	y.parent = x.parent
	if x.parent == nil {
		rbRoot = y
	} else if x == x.parent.right {
		x.parent.right = y
	} else {
		x.parent.left = y
	}
	y.right = x
	x.parent = y
}

func fixInsert(z *rbNode) {
	for z.parent != nil && z.parent.color == red {
		gp := z.parent.parent
		if z.parent == gp.left {
			y := gp.right
			if y != nil && y.color == red {
				z.parent.color = black
				y.color = black
				gp.color = red
				z = gp
			} else {
				if z == z.parent.right {
					z = z.parent
					rotateLeftRB(z)
				}
				z.parent.color = black
				z.parent.parent.color = red
				rotateRightRB(z.parent.parent)
			}
		} else {
			y := gp.left
			if y != nil && y.color == red {
				z.parent.color = black
				y.color = black
				gp.color = red
				z = gp
			} else {
				if z == z.parent.left {
					z = z.parent
					rotateRightRB(z)
				}
				z.parent.color = black
				z.parent.parent.color = red
				rotateLeftRB(z.parent.parent)
			}
		}
	}
	rbRoot.color = black
}

func insertKey(key int) {
	var y *rbNode
	x := rbRoot
	for x != nil {
		y = x
		if key < x.key {
			x = x.left
		} else if key > x.key {
			x = x.right
		} else {
			return
		}
	}
	node := &rbNode{key: key, color: red, parent: y}
	if y == nil {
		rbRoot = node
	} else if key < y.key {
		y.left = node
	} else {
		y.right = node
	}
	fixInsert(node)
}

func inorderRB(node *rbNode, result *[]int) {
	if node == nil {
		return
	}
	inorderRB(node.left, result)
	*result = append(*result, node.key)
	inorderRB(node.right, result)
}

// RbInsertInorder inserts elements into a Red-Black tree and returns inorder traversal.
func RbInsertInorder(arr []int) []int {
	rbRoot = nil
	for _, val := range arr {
		insertKey(val)
	}
	result := []int{}
	inorderRB(rbRoot, &result)
	return result
}

import java.util.ArrayList;
import java.util.List;

public class RedBlackTree {

    private static final boolean RED = true;
    private static final boolean BLACK = false;

    private static int[] keys;
    private static int[] lefts;
    private static int[] rights;
    private static int[] parents;
    private static boolean[] colors;
    private static int size;
    private static int root;

    private static void init(int capacity) {
        keys = new int[capacity];
        lefts = new int[capacity];
        rights = new int[capacity];
        parents = new int[capacity];
        colors = new boolean[capacity];
        size = 0;
        root = -1;
    }

    private static int newNode(int key) {
        int idx = size++;
        keys[idx] = key;
        lefts[idx] = -1;
        rights[idx] = -1;
        parents[idx] = -1;
        colors[idx] = RED;
        return idx;
    }

    private static void rotateLeft(int x) {
        int y = rights[x];
        rights[x] = lefts[y];
        if (lefts[y] != -1) parents[lefts[y]] = x;
        parents[y] = parents[x];
        if (parents[x] == -1) root = y;
        else if (x == lefts[parents[x]]) lefts[parents[x]] = y;
        else rights[parents[x]] = y;
        lefts[y] = x;
        parents[x] = y;
    }

    private static void rotateRight(int x) {
        int y = lefts[x];
        lefts[x] = rights[y];
        if (rights[y] != -1) parents[rights[y]] = x;
        parents[y] = parents[x];
        if (parents[x] == -1) root = y;
        else if (x == rights[parents[x]]) rights[parents[x]] = y;
        else lefts[parents[x]] = y;
        rights[y] = x;
        parents[x] = y;
    }

    private static void fixInsert(int z) {
        while (z != root && colors[parents[z]] == RED) {
            int gp = parents[parents[z]];
            if (parents[z] == lefts[gp]) {
                int y = rights[gp];
                if (y != -1 && colors[y] == RED) {
                    colors[parents[z]] = BLACK;
                    colors[y] = BLACK;
                    colors[gp] = RED;
                    z = gp;
                } else {
                    if (z == rights[parents[z]]) {
                        z = parents[z];
                        rotateLeft(z);
                    }
                    colors[parents[z]] = BLACK;
                    colors[parents[parents[z]]] = RED;
                    rotateRight(parents[parents[z]]);
                }
            } else {
                int y = lefts[gp];
                if (y != -1 && colors[y] == RED) {
                    colors[parents[z]] = BLACK;
                    colors[y] = BLACK;
                    colors[gp] = RED;
                    z = gp;
                } else {
                    if (z == lefts[parents[z]]) {
                        z = parents[z];
                        rotateRight(z);
                    }
                    colors[parents[z]] = BLACK;
                    colors[parents[parents[z]]] = RED;
                    rotateLeft(parents[parents[z]]);
                }
            }
        }
        colors[root] = BLACK;
    }

    private static void insert(int key) {
        int y = -1;
        int x = root;
        while (x != -1) {
            y = x;
            if (key < keys[x]) x = lefts[x];
            else if (key > keys[x]) x = rights[x];
            else return;
        }
        int node = newNode(key);
        parents[node] = y;
        if (y == -1) root = node;
        else if (key < keys[y]) lefts[y] = node;
        else rights[y] = node;
        fixInsert(node);
    }

    private static void inorder(int node, List<Integer> result) {
        if (node == -1) return;
        inorder(lefts[node], result);
        result.add(keys[node]);
        inorder(rights[node], result);
    }

    public static int[] rbInsertInorder(int[] arr) {
        init(arr.length + 1);
        for (int val : arr) insert(val);
        List<Integer> result = new ArrayList<>();
        inorder(root, result);
        return result.stream().mapToInt(Integer::intValue).toArray();
    }
}

fun rbInsertInorder(arr: IntArray): IntArray {
    class Node(val key: Int) {
        var left: Node? = null
        var right: Node? = null
        var parent: Node? = null
        var color: Boolean = true // true = RED
    }

    var root: Node? = null

    fun rotateLeft(x: Node) {
        val y = x.right!!
        x.right = y.left
        if (y.left != null) y.left!!.parent = x
        y.parent = x.parent
        if (x.parent == null) root = y
        else if (x == x.parent!!.left) x.parent!!.left = y
        else x.parent!!.right = y
        y.left = x
        x.parent = y
    }

    fun rotateRight(x: Node) {
        val y = x.left!!
        x.left = y.right
        if (y.right != null) y.right!!.parent = x
        y.parent = x.parent
        if (x.parent == null) root = y
        else if (x == x.parent!!.right) x.parent!!.right = y
        else x.parent!!.left = y
        y.right = x
        x.parent = y
    }

    fun fixInsert(z: Node) {
        var node = z
        while (node.parent != null && node.parent!!.color) {
            val gp = node.parent!!.parent!!
            if (node.parent == gp.left) {
                val y = gp.right
                if (y != null && y.color) {
                    node.parent!!.color = false
                    y.color = false
                    gp.color = true
                    node = gp
                } else {
                    if (node == node.parent!!.right) {
                        node = node.parent!!
                        rotateLeft(node)
                    }
                    node.parent!!.color = false
                    node.parent!!.parent!!.color = true
                    rotateRight(node.parent!!.parent!!)
                }
            } else {
                val y = gp.left
                if (y != null && y.color) {
                    node.parent!!.color = false
                    y.color = false
                    gp.color = true
                    node = gp
                } else {
                    if (node == node.parent!!.left) {
                        node = node.parent!!
                        rotateRight(node)
                    }
                    node.parent!!.color = false
                    node.parent!!.parent!!.color = true
                    rotateLeft(node.parent!!.parent!!)
                }
            }
        }
        root!!.color = false
    }

    fun insert(key: Int) {
        var y: Node? = null
        var x = root
        while (x != null) {
            y = x
            x = if (key < x.key) x.left else if (key > x.key) x.right else return
        }
        val node = Node(key)
        node.parent = y
        if (y == null) root = node
        else if (key < y.key) y.left = node
        else y.right = node
        fixInsert(node)
    }

    fun inorder(node: Node?, result: MutableList<Int>) {
        if (node == null) return
        inorder(node.left, result)
        result.add(node.key)
        inorder(node.right, result)
    }

    for (v in arr) insert(v)
    val result = mutableListOf<Int>()
    inorder(root, result)
    return result.toIntArray()
}

