    RED = True
    BLACK = False

    class Node:
        def __init__(self, key: int):
            self.key = key
            self.left: 'Node | None' = None
            self.right: 'Node | None' = None
            self.parent: 'Node | None' = None
            self.color: bool = RED

    root: Node | None = None

    def rotate_left(x: Node) -> None:
        nonlocal root
        y = x.right
        x.right = y.left
        if y.left:
            y.left.parent = x
        y.parent = x.parent
        if x.parent is None:
            root = y
        elif x == x.parent.left:
            x.parent.left = y
        else:
            x.parent.right = y
        y.left = x
        x.parent = y

    def rotate_right(x: Node) -> None:
        nonlocal root
        y = x.left
        x.left = y.right
        if y.right:
            y.right.parent = x
        y.parent = x.parent
        if x.parent is None:
            root = y
        elif x == x.parent.right:
            x.parent.right = y
        else:
            x.parent.left = y
        y.right = x
        x.parent = y

    def fix_insert(z: Node) -> None:
        nonlocal root
        while z.parent and z.parent.color == RED:
            if z.parent == z.parent.parent.left if z.parent.parent else False:
                y = z.parent.parent.right
                if y and y.color == RED:
                    z.parent.color = BLACK
                    y.color = BLACK
                    z.parent.parent.color = RED
                    z = z.parent.parent
                else:
                    if z == z.parent.right:
                        z = z.parent
                        rotate_left(z)
                    z.parent.color = BLACK
                    z.parent.parent.color = RED
                    rotate_right(z.parent.parent)
            else:
                y = z.parent.parent.left if z.parent.parent else None
                if y and y.color == RED:
                    z.parent.color = BLACK
                    y.color = BLACK
                    z.parent.parent.color = RED
                    z = z.parent.parent
                else:
                    if z == z.parent.left:
                        z = z.parent
                        rotate_right(z)
                    z.parent.color = BLACK
                    z.parent.parent.color = RED
                    rotate_left(z.parent.parent)
        root.color = BLACK

    def insert(key: int) -> None:
        nonlocal root
        node = Node(key)
        y = None
        x = root
        while x:
            y = x
            if key < x.key:
                x = x.left
            elif key > x.key:
                x = x.right
            else:
                return  # duplicate
        node.parent = y
        if y is None:
            root = node
        elif key < y.key:
            y.left = node
        else:
            y.right = node
        fix_insert(node)

    def inorder(node: 'Node | None', result: list[int]) -> None:
        if node:
            inorder(node.left, result)
            result.append(node.key)
            inorder(node.right, result)

    for val in arr:
        insert(val)

    result: list[int] = []
    inorder(root, result)
    return result

pub fn rb_insert_inorder(arr: &[i32]) -> Vec<i32> {
    #[derive(Clone, Copy, PartialEq)]
    enum Color { Red, Black }

    struct Node {
        key: i32,
        left: i32,
        right: i32,
        parent: i32,
        color: Color,
    }

    let mut nodes: Vec<Node> = Vec::new();
    let mut root: i32 = -1;

    fn new_node(nodes: &mut Vec<Node>, key: i32) -> i32 {
        let idx = nodes.len() as i32;
        nodes.push(Node { key, left: -1, right: -1, parent: -1, color: Color::Red });
        idx
    }

    fn rotate_left(nodes: &mut Vec<Node>, root: &mut i32, x: i32) {
        let y = nodes[x as usize].right;
        nodes[x as usize].right = nodes[y as usize].left;
        if nodes[y as usize].left != -1 {
            nodes[nodes[y as usize].left as usize].parent = x;
        }
        nodes[y as usize].parent = nodes[x as usize].parent;
        if nodes[x as usize].parent == -1 { *root = y; }
        else if x == nodes[nodes[x as usize].parent as usize].left {
            nodes[nodes[x as usize].parent as usize].left = y;
        } else {
            nodes[nodes[x as usize].parent as usize].right = y;
        }
        nodes[y as usize].left = x;
        nodes[x as usize].parent = y;
    }

    fn rotate_right(nodes: &mut Vec<Node>, root: &mut i32, x: i32) {
        let y = nodes[x as usize].left;
        nodes[x as usize].left = nodes[y as usize].right;
        if nodes[y as usize].right != -1 {
            nodes[nodes[y as usize].right as usize].parent = x;
        }
        nodes[y as usize].parent = nodes[x as usize].parent;
        if nodes[x as usize].parent == -1 { *root = y; }
        else if x == nodes[nodes[x as usize].parent as usize].right {
            nodes[nodes[x as usize].parent as usize].right = y;
        } else {
            nodes[nodes[x as usize].parent as usize].left = y;
        }
        nodes[y as usize].right = x;
        nodes[x as usize].parent = y;
    }

    fn fix_insert(nodes: &mut Vec<Node>, root: &mut i32, mut z: i32) {
        while z != *root && nodes[nodes[z as usize].parent as usize].color == Color::Red {
            let p = nodes[z as usize].parent;
            let gp = nodes[p as usize].parent;
            if p == nodes[gp as usize].left {
                let y = nodes[gp as usize].right;
                if y != -1 && nodes[y as usize].color == Color::Red {
                    nodes[p as usize].color = Color::Black;
                    nodes[y as usize].color = Color::Black;
                    nodes[gp as usize].color = Color::Red;
                    z = gp;
                } else {
                    if z == nodes[p as usize].right {
                        z = p;
                        rotate_left(nodes, root, z);
                    }
                    let p2 = nodes[z as usize].parent;
                    let gp2 = nodes[p2 as usize].parent;
                    nodes[p2 as usize].color = Color::Black;
                    nodes[gp2 as usize].color = Color::Red;
                    rotate_right(nodes, root, gp2);
                }
            } else {
                let y = nodes[gp as usize].left;
                if y != -1 && nodes[y as usize].color == Color::Red {
                    nodes[p as usize].color = Color::Black;
                    nodes[y as usize].color = Color::Black;
                    nodes[gp as usize].color = Color::Red;
                    z = gp;
                } else {
                    if z == nodes[p as usize].left {
                        z = p;
                        rotate_right(nodes, root, z);
                    }
                    let p2 = nodes[z as usize].parent;
                    let gp2 = nodes[p2 as usize].parent;
                    nodes[p2 as usize].color = Color::Black;
                    nodes[gp2 as usize].color = Color::Red;
                    rotate_left(nodes, root, gp2);
                }
            }
        }
        nodes[*root as usize].color = Color::Black;
    }

    fn insert_key(nodes: &mut Vec<Node>, root: &mut i32, key: i32) {
        let mut y: i32 = -1;
        let mut x = *root;
        while x != -1 {
            y = x;
            if key < nodes[x as usize].key { x = nodes[x as usize].left; }
            else if key > nodes[x as usize].key { x = nodes[x as usize].right; }
            else { return; }
        }
        let node = new_node(nodes, key);
        nodes[node as usize].parent = y;
        if y == -1 { *root = node; }
        else if key < nodes[y as usize].key { nodes[y as usize].left = node; }
        else { nodes[y as usize].right = node; }
        fix_insert(nodes, root, node);
    }

    fn inorder(nodes: &Vec<Node>, node: i32, result: &mut Vec<i32>) {
        if node == -1 { return; }
        inorder(nodes, nodes[node as usize].left, result);
        result.push(nodes[node as usize].key);
        inorder(nodes, nodes[node as usize].right, result);
    }

    for &val in arr {
        insert_key(&mut nodes, &mut root, val);
    }
    let mut result = Vec::new();
    inorder(&nodes, root, &mut result);
    result
}

object RedBlackTree {

  private val RED = true
  private val BLACK = false

  private class Node(val key: Int) {
    var left: Node = _
    var right: Node = _
    var parent: Node = _
    var color: Boolean = RED
  }

  def rbInsertInorder(arr: Array[Int]): Array[Int] = {
    var root: Node = null

    def rotateLeft(x: Node): Unit = {
      val y = x.right
      x.right = y.left
      if (y.left != null) y.left.parent = x
      y.parent = x.parent
      if (x.parent == null) root = y
      else if (x eq x.parent.left) x.parent.left = y
      else x.parent.right = y
      y.left = x
      x.parent = y
    }

    def rotateRight(x: Node): Unit = {
      val y = x.left
      x.left = y.right
      if (y.right != null) y.right.parent = x
      y.parent = x.parent
      if (x.parent == null) root = y
      else if (x eq x.parent.right) x.parent.right = y
      else x.parent.left = y
      y.right = x
      x.parent = y
    }

    def fixInsert(z0: Node): Unit = {
      var z = z0
      while (z.parent != null && z.parent.color == RED) {
        val gp = z.parent.parent
        if (z.parent eq gp.left) {
          val y = gp.right
          if (y != null && y.color == RED) {
            z.parent.color = BLACK
            y.color = BLACK
            gp.color = RED
            z = gp
          } else {
            if (z eq z.parent.right) { z = z.parent; rotateLeft(z) }
            z.parent.color = BLACK
            z.parent.parent.color = RED
            rotateRight(z.parent.parent)
          }
        } else {
          val y = gp.left
          if (y != null && y.color == RED) {
            z.parent.color = BLACK
            y.color = BLACK
            gp.color = RED
            z = gp
          } else {
            if (z eq z.parent.left) { z = z.parent; rotateRight(z) }
            z.parent.color = BLACK
            z.parent.parent.color = RED
            rotateLeft(z.parent.parent)
          }
        }
      }
      root.color = BLACK
    }

    def insert(key: Int): Unit = {
      var y: Node = null
      var x = root
      while (x != null) {
        y = x
        if (key < x.key) x = x.left
        else if (key > x.key) x = x.right
        else return
      }
      val node = new Node(key)
      node.parent = y
      if (y == null) root = node
      else if (key < y.key) y.left = node
      else y.right = node
      fixInsert(node)
    }

    def inorder(node: Node, result: scala.collection.mutable.ListBuffer[Int]): Unit = {
      if (node == null) return
      inorder(node.left, result)
      result += node.key
      inorder(node.right, result)
    }

    for (v <- arr) insert(v)
    val result = scala.collection.mutable.ListBuffer[Int]()
    inorder(root, result)
    result.toArray
  }
}

class RBNode {
    var key: Int
    var left: RBNode?
    var right: RBNode?
    var parent: RBNode?
    var isRed: Bool

    init(_ key: Int) {
        self.key = key
        self.left = nil
        self.right = nil
        self.parent = nil
        self.isRed = true
    }
}

func rbInsertInorder(_ arr: [Int]) -> [Int] {
    var root: RBNode? = nil

    func rotateLeft(_ x: RBNode) {
        let y = x.right!
        x.right = y.left
        if y.left != nil { y.left!.parent = x }
        y.parent = x.parent
        if x.parent == nil { root = y }
        else if x === x.parent!.left { x.parent!.left = y }
        else { x.parent!.right = y }
        y.left = x
        x.parent = y
    }

    func rotateRight(_ x: RBNode) {
        let y = x.left!
        x.left = y.right
        if y.right != nil { y.right!.parent = x }
        y.parent = x.parent
        if x.parent == nil { root = y }
        else if x === x.parent!.right { x.parent!.right = y }
        else { x.parent!.left = y }
        y.right = x
        x.parent = y
    }

    func fixInsert(_ node: RBNode) {
        var z = node
        while z.parent != nil && z.parent!.isRed {
            let gp = z.parent!.parent!
            if z.parent === gp.left {
                let y = gp.right
                if y != nil && y!.isRed {
                    z.parent!.isRed = false
                    y!.isRed = false
                    gp.isRed = true
                    z = gp
                } else {
                    if z === z.parent!.right {
                        z = z.parent!
                        rotateLeft(z)
                    }
                    z.parent!.isRed = false
                    z.parent!.parent!.isRed = true
                    rotateRight(z.parent!.parent!)
                }
            } else {
                let y = gp.left
                if y != nil && y!.isRed {
                    z.parent!.isRed = false
                    y!.isRed = false
                    gp.isRed = true
                    z = gp
                } else {
                    if z === z.parent!.left {
                        z = z.parent!
                        rotateRight(z)
                    }
                    z.parent!.isRed = false
                    z.parent!.parent!.isRed = true
                    rotateLeft(z.parent!.parent!)
                }
            }
        }
        root!.isRed = false
    }

    func insert(_ key: Int) {
        var y: RBNode? = nil
        var x = root
        while x != nil {
            y = x
            if key < x!.key { x = x!.left }
            else if key > x!.key { x = x!.right }
            else { return }
        }
        let node = RBNode(key)
        node.parent = y
        if y == nil { root = node }
        else if key < y!.key { y!.left = node }
        else { y!.right = node }
        fixInsert(node)
    }

    func inorder(_ node: RBNode?, _ result: inout [Int]) {
        guard let node = node else { return }
        inorder(node.left, &result)
        result.append(node.key)
        inorder(node.right, &result)
    }

    for val in arr { insert(val) }
    var result: [Int] = []
    inorder(root, &result)
    return result
}

